      "item_cd(상품코드, text)",
      "tmzon_div(시간대 00~23, text)",
      "sale_qty(판매수량, text→CAST(sale_qty AS NUMERIC)로 집계)",
      "sale_amt(매출금액, text→CAST(sale_amt AS NUMERIC)로 집계)"
    ]
  }
}

