{
  "sql": "SELECT \"ITEM_NM\", SUM(COALESCE(\"PROD_QTY\", 0) + COALESCE(\"PROD_QTY_2\", 0) + COALESCE(\"PROD_QTY_3\", 0)) AS total_prod_qty FROM \"PROD_DTL\" WHERE \"MASKED_STOR_CD\" = :store_id AND \"SALE_DT\" = TO_CHAR(CURRENT_DATE - INTERVAL '1 day', 'YYYYMMDD') AND \"ITEM_NM\" LIKE '%소금%우유%도넛%' GROUP BY \"ITEM_NM\" LIMIT 200;",
